from lxml import etree

def process_soap_request(soap_xml, dtd_path):
    # Parse the XML with DTD validation
    with open(dtd_path, 'rb') as dtd_file:
        dtd = etree.DTD(dtd_file)

    parser = etree.XMLParser(dtd_validation=True)
    try:
        tree = etree.fromstring(soap_xml.encode(), parser)
    except etree.XMLSyntaxError as e:
        return f"XML Syntax Error: {e}"

    # Check if the document conforms to the DTD
    if not dtd.validate(tree):
        return "DTD Validation failed: " + str(dtd.error_log.filter_from_errors())

    # Extract the body from the SOAP envelope
    namespaces = {'soap': 'http://schemas.xmlsoap.org/soap/envelope/'}
    body = tree.find('soap:Body', namespaces)

    if body is None:
        return "No SOAP Body found in the request"
    
    # Convert the body to string and return
    return etree.tostring(body, pretty_print=True).decode()

# Example usage:
soap_message = '''<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
<soap:Body>
   <m:GetPrice xmlns:m="http://www.example.org/stock">
       <m:StockName>IBM</m:StockName>
   </m:GetPrice>
</soap:Body>
</soap:Envelope>'''

dtd_path = 'path/to/soap.dtd'  # Replace with the path to your DTD file
result = process_soap_request(soap_message, dtd_path)
print(result)